import os
import openai
from langchain.embeddings import OpenAIEmbeddings
from langchain.vectorstores import FAISS
from langchain.chains import RetrievalQA
from langchain.llms import OpenAI
from langchain.document_loaders import TextLoader
from langchain.text_splitter import RecursiveCharacterTextSplitter

# Load environment variables
openai.api_key = os.getenv("OPENAI_API_KEY")

# Load and process company documents
def load_documents(directory):
    documents = []
    for filename in os.listdir(directory):
        if filename.endswith('.txt'):
            loader = TextLoader(os.path.join(directory, filename))
            documents.extend(loader.load())
    return documents

# Split documents into manageable chunks
def split_documents(documents):
    text_splitter = RecursiveCharacterTextSplitter(chunk_size=1000, chunk_overlap=100)
    return text_splitter.split_documents(documents)

# Create vector store
def create_vector_store(documents):
    embeddings = OpenAIEmbeddings()
    vector_store = FAISS.from_documents(documents, embeddings)
    return vector_store

# Initialize RAG system
def initialize_rag_system(directory):
    documents = load_documents(directory)
    split_docs = split_documents(documents)
    vector_store = create_vector_store(split_docs)
    llm = OpenAI(temperature=0)
    rag_system = RetrievalQA(llm=llm, retriever=vector_store.as_retriever())
    return rag_system

# Query the RAG system
def query_rag_system(rag_system, query):
    response = rag_system.run(query)
    return response

# Example usage
if __name__ == "__main__":
    directory = "path/to/company/documents"
    rag_system = initialize_rag_system(directory)
    
    user_query = input("Enter your query: ")
    answer = query_rag_system(rag_system, user_query)
    print("Answer:", answer)